// Compute this week's summary (last 7 days)
const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
const items = $input.all();

let total = 0, hot = 0, enrolled = 0;
const cityCount = {};
const courseCount = {};
const sourceCount = {};

for (const item of items) {
  const ts = new Date(item.json.Timestamp || 0).getTime();
  if (ts < sevenDaysAgo) continue;
  total++;
  if (item.json['Lead Score'] === 'Hot') hot++;
  if (String(item.json['Lead Status']).toLowerCase() === 'enrolled') enrolled++;
  const city = item.json.City || 'Unknown';
  cityCount[city] = (cityCount[city] || 0) + 1;
  const course = item.json['Course Interest'] || 'Unknown';
  courseCount[course] = (courseCount[course] || 0) + 1;
  const src = item.json['Source Channel'] || 'Other';
  sourceCount[src] = (sourceCount[src] || 0) + 1;
}

const topCities = Object.entries(cityCount).sort(([,a],[,b])=>b-a).slice(0,3).map(([k,v])=>`${k}(${v})`).join(', ');
const topCourses = Object.entries(courseCount).sort(([,a],[,b])=>b-a).slice(0,3).map(([k,v])=>`${k}(${v})`).join(', ');
const topSources = Object.entries(sourceCount).sort(([,a],[,b])=>b-a).map(([k,v])=>`${k}:${v}`).join(', ');
const convRate = total > 0 ? ((enrolled/total)*100).toFixed(1) : '0';

return [{ json: { total, hot, enrolled, topCities, topCourses, topSources, convRate } }];

